# GastroIQ Deploy Script - alessio.steinike
# Ausfuehren: .\gastroiq-deploy.ps1

Set-Location "C:\Users\alessio.steinike\Documents\gastroiq"
$ErrorActionPreference = "Stop"

function Write-Step { param($n, $t) Write-Host "`n[$n] $t" -ForegroundColor Cyan }
function Write-OK   { param($t) Write-Host "    OK: $t" -ForegroundColor Green }
function Write-Warn { param($t) Write-Host "    WARN: $t" -ForegroundColor Yellow }
function WriteFile  { param($path, $b64) $bytes = [Convert]::FromBase64String($b64); $full = Join-Path (Get-Location).Path $path; New-Item -ItemType Directory -Force -Path (Split-Path $full) | Out-Null; [IO.File]::WriteAllBytes($full, $bytes) }

Write-Host "`n================================================" -ForegroundColor Magenta
Write-Host "  GastroIQ Deploy Script" -ForegroundColor Magenta
Write-Host "================================================`n" -ForegroundColor Magenta

# === 1. vercel.json ===
Write-Step "1/7" "vercel.json schreiben"
WriteFile "vercel.json" ""
Write-OK "vercel.json"

# === 2. SQL Migration ===
Write-Step "2/7" "RLS SQL Migration schreiben"
New-Item -ItemType Directory -Force -Path "supabase\migrations" | Out-Null
WriteFile "supabase\migrations\001_rls_fix.sql" ""
Write-OK "001_rls_fix.sql"

# === 3. SQL ausfuehren ===
Write-Step "3/7" "RLS Fix in Supabase ausfuehren"
try {
    Get-Content "supabase\migrations\001_rls_fix.sql" -Raw | supabase db execute --project-ref vrksgszggavczivojqvr
    Write-OK "RLS Policies gesetzt"
} catch {
    Write-Warn "SQL fehlgeschlagen - bitte manuell im Supabase SQL Editor ausfuehren: supabase\migrations\001_rls_fix.sql"
}

# === 4. Edge Functions schreiben ===
Write-Step "4/7" "Edge Functions schreiben"
New-Item -ItemType Directory -Force -Path "supabase\functions\stripe-webhook" | Out-Null
New-Item -ItemType Directory -Force -Path "supabase\functions\delete-user-data" | Out-Null
WriteFile "supabase\functions\stripe-webhook\index.ts" ""
WriteFile "supabase\functions\delete-user-data\index.ts" ""
Write-OK "Edge Functions geschrieben"

# === 5. Edge Functions deployen ===
Write-Step "5/7" "Edge Functions deployen"
try {
    Write-Host "    Deploying stripe-webhook..." -ForegroundColor Gray
    supabase functions deploy stripe-webhook --no-verify-jwt --project-ref vrksgszggavczivojqvr
    Write-OK "stripe-webhook deployed"
} catch { Write-Warn "stripe-webhook deploy fehlgeschlagen: $_" }
try {
    Write-Host "    Deploying delete-user-data..." -ForegroundColor Gray
    supabase functions deploy delete-user-data --project-ref vrksgszggavczivojqvr
    Write-OK "delete-user-data deployed"
} catch { Write-Warn "delete-user-data deploy fehlgeschlagen: $_" }

# === 6. HTML Seiten schreiben ===
Write-Step "6/7" "HTML-Seiten schreiben"
WriteFile "404.html" ""
WriteFile "impressum.html" ""
WriteFile "datenschutz.html" ""
WriteFile "agb.html" ""
New-Item -ItemType Directory -Force -Path "patches" | Out-Null
WriteFile "patches\cookie-consent-banner.html" ""
Write-OK "Alle HTML-Seiten erstellt"

# === 7. Git push ===
Write-Step "7/7" "Git commit und push"
git add -A
git commit -m "feat: security headers, RLS fix, edge functions, legal pages, cookie consent, 404"
git push

Write-Host "`n================================================" -ForegroundColor Green
Write-Host "  DEPLOY ABGESCHLOSSEN!" -ForegroundColor Green
Write-Host "================================================" -ForegroundColor Green
Write-Host ""
Write-Host "Noch manuell noetig:" -ForegroundColor Yellow
Write-Host "  1. Platzhalter [ ... ] in impressum.html, datenschutz.html, agb.html ausfuellen" -ForegroundColor White
Write-Host "  2. Cookie-Banner: patches\cookie-consent-banner.html vor </body> in gastroiq.html einfuegen" -ForegroundColor White
Write-Host "  3. Stripe Tax aktivieren: dashboard.stripe.com/tax" -ForegroundColor White
Write-Host "  4. Anwalt: AGB + Datenschutz pruefen lassen" -ForegroundColor White
Write-Host ""
Write-Host "Testen:" -ForegroundColor Yellow
Write-Host "  securityheaders.com mit gastroiq.de (Ziel: A+)" -ForegroundColor White
Write-Host "  /impressum /datenschutz /agb /404-test aufrufen" -ForegroundColor White
